import type { ChatLanguage, ChatMessage } from "@/lib/types";
import MessageBubble from "./MessageBubble";

type Props = {
  messages: ChatMessage[];
  input: string;
  onInputChange: (value: string) => void;
  onSend: () => void;
  isStreaming: boolean;
  language: ChatLanguage;
  onLanguageChange: (value: ChatLanguage) => void;
  error: string | null;
};

export default function ChatWindow({
  messages,
  input,
  onInputChange,
  onSend,
  isStreaming,
  language,
  onLanguageChange,
  error
}: Props) {
  return (
    <section className="flex h-full flex-1 flex-col bg-slate-50">
      <header className="flex items-center justify-between border-b border-slate-200 bg-white px-4 py-3">
        <div>
          <p className="text-sm font-semibold text-slate-700">Chat</p>
          <p className="text-xs text-slate-500">
            This tool does not include or reproduce the AP Stylebook.
          </p>
        </div>
        <div className="flex items-center gap-2 text-xs text-slate-600">
          <span>Language</span>
          <select
            className="rounded-md border border-slate-300 bg-white px-2 py-1 text-xs"
            value={language}
            onChange={(event) =>
              onLanguageChange(event.target.value as ChatLanguage)
            }
          >
            <option value="en">EN</option>
            <option value="es">ES</option>
          </select>
        </div>
      </header>
      <div className="flex-1 overflow-y-auto px-6 py-4">
        {messages.length === 0 && (
          <div className="rounded-xl border border-dashed border-slate-200 bg-white p-6 text-sm text-slate-500">
            Start a conversation or select one from the sidebar.
          </div>
        )}
        <div className="space-y-4">
          {messages.map((message) => (
            <MessageBubble key={message.id} message={message} />
          ))}
        </div>
      </div>
      <div className="border-t border-slate-200 bg-white px-4 py-3">
        {error && <p className="mb-2 text-xs text-rose-600">{error}</p>}
        <div className="flex items-center gap-2">
          <textarea
            className="min-h-[48px] w-full resize-none rounded-md border border-slate-300 px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-slate-400"
            placeholder="Send a message..."
            value={input}
            onChange={(event) => onInputChange(event.target.value)}
            onKeyDown={(event) => {
              if (event.key === "Enter" && !event.shiftKey) {
                event.preventDefault();
                onSend();
              }
            }}
          />
          <button
            className="rounded-md bg-slate-900 px-4 py-2 text-sm font-semibold text-white disabled:opacity-50"
            onClick={onSend}
            disabled={isStreaming || !input.trim()}
          >
            {isStreaming ? "Sending..." : "Send"}
          </button>
        </div>
      </div>
    </section>
  );
}
