"use client";

import { useEffect, useMemo, useState } from "react";
import type { ValidationFinding, ValidationResult } from "@/lib/types";

const sampleArticle = `CITY OF RIVERGLEN, California — The mayor said 10 percent of residents voted at 8 PM on January 12, 2026. 
“We are excited!!” she said. The company Riverglen Inc reported DOUBLE DIGIT growth.
The board includes Maria, Jose and Lee. A spokesperson noted that manpower shortages remain.`;

const severityLabels: Record<ValidationFinding["severity"], string> = {
  definite: "Definite issue",
  potential: "Potential issue",
  review: "Needs human review"
};

export default function ValidatorPanel({
  className
}: {
  className?: string;
}) {
  const [text, setText] = useState("");
  const [result, setResult] = useState<ValidationResult | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [useLLM, setUseLLM] = useState(false);
  const [status, setStatus] = useState<string | null>(null);
  const [selectedFindingId, setSelectedFindingId] = useState<string | null>(
    null
  );
  const [filters, setFilters] = useState({
    definite: true,
    potential: true,
    review: true
  });

  useEffect(() => {
    if (!selectedFindingId) return;
    const target = document.querySelector<HTMLElement>(
      `[data-finding-id="${selectedFindingId}"]`
    );
    if (target) {
      target.scrollIntoView({ behavior: "smooth", block: "center" });
      target.classList.add("ring-2", "ring-amber-500");
      setTimeout(() => {
        target.classList.remove("ring-2", "ring-amber-500");
      }, 1200);
    }
  }, [selectedFindingId, result]);

  const filteredFindings = useMemo(() => {
    if (!result) return [];
    return result.findings.filter((finding) => filters[finding.severity]);
  }, [result, filters]);

  const handleValidate = async () => {
    if (!text.trim()) {
      setStatus("Paste article text before validating.");
      return;
    }
    setIsLoading(true);
    setStatus(null);
    setSelectedFindingId(null);
    try {
      const response = await fetch("/api/validate", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ text, useLLM })
      });
      if (!response.ok) {
        throw new Error("Validation failed");
      }
      const data = (await response.json()) as ValidationResult;
      setResult(data);
    } catch {
      setStatus("Validation failed. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleApplySuggestion = (finding: ValidationFinding) => {
    if (!finding.suggestion) return;
    setText((prev) => prev.slice(0, finding.start) + finding.suggestion + prev.slice(finding.end));
    setStatus("Suggestion applied. Re-run validation for updated results.");
    setResult(null);
  };

  const handleCopyJson = async () => {
    if (!result) return;
    await navigator.clipboard.writeText(JSON.stringify(result, null, 2));
    setStatus("Report copied to clipboard.");
  };

  const handleDownloadJson = () => {
    if (!result) return;
    const blob = new Blob([JSON.stringify(result, null, 2)], {
      type: "application/json"
    });
    const url = URL.createObjectURL(blob);
    const anchor = document.createElement("a");
    anchor.href = url;
    anchor.download = "validation-report.json";
    anchor.click();
    URL.revokeObjectURL(url);
  };

  return (
    <section
      className={`flex h-full flex-col border-l border-slate-200 bg-white ${className ?? ""}`}
    >
      <header className="border-b border-slate-200 px-4 py-3">
        <h2 className="text-sm font-semibold text-slate-800">
          AP Style Validator (Heuristic)
        </h2>
        <p className="text-xs text-slate-500">
          This tool does not include or reproduce the AP Stylebook. It uses
          configurable heuristics and internal rules.
        </p>
      </header>

      <div className="flex-1 overflow-y-auto px-4 py-4">
        <div className="space-y-3">
          <textarea
            className="min-h-[180px] w-full rounded-md border border-slate-300 px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-slate-400"
            placeholder="Paste article text here..."
            value={text}
            onChange={(event) => setText(event.target.value)}
          />
          <div className="flex flex-wrap items-center gap-2 text-xs text-slate-600">
            <button
              className="rounded-md border border-slate-300 px-2 py-1"
              onClick={() => setText(sampleArticle)}
            >
              Load sample article
            </button>
            <label className="flex items-center gap-2">
              <input
                type="checkbox"
                checked={useLLM}
                onChange={(event) => setUseLLM(event.target.checked)}
              />
              Refine findings with AI (optional)
            </label>
            <button
              className="ml-auto rounded-md bg-slate-900 px-3 py-1.5 text-white disabled:opacity-50"
              onClick={handleValidate}
              disabled={isLoading}
            >
              {isLoading ? "Validating..." : "Validate"}
            </button>
          </div>
          {status && <p className="text-xs text-amber-700">{status}</p>}
        </div>

        {!result && (
          <div className="mt-6 rounded-xl border border-dashed border-slate-200 bg-slate-50 p-4 text-xs text-slate-500">
            Run validation to see a structured report, findings list, and
            annotated article.
          </div>
        )}

        {result && (
          <div className="mt-6 space-y-6">
            <div className="rounded-xl border border-slate-200 bg-slate-50 p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-xs uppercase tracking-wide text-slate-500">
                    Overall Score
                  </p>
                  <p className="text-2xl font-semibold text-slate-900">
                    {result.score}
                  </p>
                </div>
                <div className="text-xs text-slate-500">
                  {result.meta.model ? `Model: ${result.meta.model}` : "Rules only"}
                </div>
              </div>
              <div className="mt-3 grid grid-cols-2 gap-2 text-xs sm:grid-cols-3">
                {Object.entries(result.categories).map(([category, entry]) => (
                  <div
                    key={category}
                    className="rounded-md bg-white px-3 py-2"
                  >
                    <p className="font-semibold text-slate-700">{category}</p>
                    <p className="text-slate-500">
                      Score {entry.score} · {entry.count} findings
                    </p>
                  </div>
                ))}
              </div>
            </div>

            <div className="rounded-xl border border-slate-200 bg-white p-4">
              <div className="flex items-center justify-between">
                <p className="text-sm font-semibold text-slate-700">
                  Findings ({result.findings.length})
                </p>
                <div className="flex gap-2 text-xs">
                  {(["definite", "potential", "review"] as const).map(
                    (severity) => (
                      <label key={severity} className="flex items-center gap-1">
                        <input
                          type="checkbox"
                          checked={filters[severity]}
                          onChange={(event) =>
                            setFilters((prev) => ({
                              ...prev,
                              [severity]: event.target.checked
                            }))
                          }
                        />
                        {severityLabels[severity]}
                      </label>
                    )
                  )}
                </div>
              </div>
              <div className="mt-3 space-y-3 text-xs">
                {filteredFindings.length === 0 && (
                  <p className="text-slate-500">No findings in this filter.</p>
                )}
                {filteredFindings.map((finding) => (
                  <div
                    key={finding.id}
                    className="rounded-md border border-slate-100 bg-slate-50 p-3"
                  >
                    <div className="flex items-center justify-between">
                      <div>
                        <p className="font-semibold text-slate-700">
                          {finding.category}
                        </p>
                        <p className="text-slate-500">
                          {severityLabels[finding.severity]} · Confidence{" "}
                          {Math.round(finding.confidence * 100)}%
                        </p>
                      </div>
                      <div className="flex gap-2">
                        <button
                          className="rounded-md border border-slate-300 px-2 py-1"
                          onClick={() => setSelectedFindingId(finding.id)}
                        >
                          View
                        </button>
                        <button
                          className="rounded-md bg-slate-900 px-2 py-1 text-white"
                          onClick={() => handleApplySuggestion(finding)}
                        >
                          Apply suggestion
                        </button>
                      </div>
                    </div>
                    <p className="mt-2 text-slate-600">
                      <span className="font-semibold text-slate-700">
                        Snippet:
                      </span>{" "}
                      “{finding.snippet}”
                    </p>
                    <p className="mt-1 text-slate-600">
                      <span className="font-semibold text-slate-700">
                        Suggestion:
                      </span>{" "}
                      {finding.suggestion}
                    </p>
                    <p className="mt-1 text-slate-600">{finding.rationale}</p>
                  </div>
                ))}
              </div>
              <div className="mt-3 flex gap-2">
                <button
                  className="rounded-md border border-slate-300 px-2 py-1 text-xs"
                  onClick={handleCopyJson}
                >
                  Copy report JSON
                </button>
                <button
                  className="rounded-md border border-slate-300 px-2 py-1 text-xs"
                  onClick={handleDownloadJson}
                >
                  Download report JSON
                </button>
              </div>
            </div>

            <div className="rounded-xl border border-slate-200 bg-white p-4">
              <p className="text-sm font-semibold text-slate-700">
                Annotated article
              </p>
              <div
                className="mt-2 max-h-[280px] overflow-y-auto rounded-md border border-slate-200 bg-slate-50 p-3 text-xs leading-6 text-slate-700"
                dangerouslySetInnerHTML={{ __html: result.annotatedText }}
              />
            </div>
          </div>
        )}
      </div>
    </section>
  );
}
